    lb = ProofBuilder(sys, "mt2d")
    h1 = lb.hyp("mt2d.1", "( φ → χ )")
    h2 = lb.hyp("mt2d.2", "( φ → ( ψ → ¬ χ ) )")
    s1 = lb.ref("s1", "( φ → ( χ → ¬ ψ ) )", h2, ref="con2d", note="con2d")
    res = lb.ref("res", "( φ → ¬ ψ )", h1, s1, ref="mpd", note="mpd")
