def prove_con3d(sys: System) -> Proof:
    """A contraposition deduction.  Deduction form of ~ con3 .  (Contributed by
    NM, 10-Jan-1993.)
    """
    lb = ProofBuilder(sys, "con3d")
    h1 = lb.hyp("con3d.1", "( φ → ( ψ → χ ) )")
    s1 = lb.ref("s1", "( ¬ ¬ ψ → ψ )", ref="notnotr", note="notnotr")
