def prove_pm2_01(sys: System) -> Proof:
    """Weak Clavius law.  If a formula implies its negation, then it is false.  A
    form of "reductio ad absurdum", which can be used in proofs by
    contradiction.  Theorem *2.01 of [WhiteheadRussell] p. 100.  Provable in
    minimal calculus, contrary to the Clavius law ~ pm2.18 .  (Contributed by
    NM, 18-Aug-1993.)  (Proof shortened by Mel L. O'Cat, 21-Nov-2008.)  (Proof
    shortened by Wolf Lammen, 31-Oct-2012.)
    """
    lb = ProofBuilder(sys, "pm2.01")
    s1 = lb.ref("s1", "( ¬ φ → ¬ φ )", ref="id", note="id")
    s2 = lb.ref("s2", "( ¬ φ → ¬ φ )", ref="id", note="id")
    res = lb.ref("res", "( ( φ → ¬ φ ) → ¬ φ )", s1, s2, ref="ja", note="ja")
    return lb.build(res)

def prove_pm2_01i(sys: System) -> Proof:
    """Inference associated with the weak Clavius law ~ pm2.01 .  (Contributed
    by BJ, 30-Mar-2020.)
    """
    lb = ProofBuilder(sys, "pm2.01i")
    h1 = lb.hyp("pm2.01i.1", "( φ → ¬ φ )")
    s1 = lb.ref("s1", "( ( φ → ¬ φ ) → ¬ φ )", ref="pm2.01", note="pm2.01")
    res = lb.mp("res", h1, s1, "ax-mp")
    return lb.build(res)

def prove_pm2_01d(sys: System) -> Proof:
    """Deduction based on reductio ad absurdum.  (Contributed by NM,
    18-Aug-1993.)  (Proof shortened by Wolf Lammen, 5-Mar-2013.)
    """
    lb = ProofBuilder(sys, "pm2.01d")
    h1 = lb.hyp("pm2.01d.1", "( φ → ( ψ → ¬ ψ ) )")
    s1 = lb.ref("s1", "( ¬ ψ → ¬ ψ )", ref="id", note="id")
    res = lb.ref("res", "( φ → ¬ ψ )", h1, s1, ref="pm2.61d1", note="pm2.61d1")
    return lb.build(res)

def prove_pm2_6(sys: System) -> Proof:
    """Theorem *2.6 of [WhiteheadRussell] p. 107.  (Contributed by NM,
    3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "pm2.6")
    s1 = lb.ref("s1", "( ( ¬ φ → ψ ) → ( ¬ φ → ψ ) )", ref="id", note="id")
    s2 = lb.ref("s2", "( ( ¬ φ → ψ ) → ( ψ → ψ ) )", ref="idd", note="idd")
    res = lb.ref("res", "( ( ¬ φ → ψ ) → ( ( φ → ψ ) → ψ ) )", s1, s2, ref="jad", note="jad")
    return lb.build(res)

def prove_pm2_61(sys: System) -> Proof:
    """Theorem *2.61 of [WhiteheadRussell] p. 107.  Useful for eliminating an
    antecedent.  (Contributed by NM, 4-Jan-1993.)  (Proof shortened by Wolf
    Lammen, 22-Sep-2013.)
    """
    lb = ProofBuilder(sys, "pm2.61")
    s1 = lb.ref("s1", "( ( ¬ φ → ψ ) → ( ( φ → ψ ) → ψ ) )", ref="pm2.6", note="pm2.6")
    res = lb.ref("res", "( ( φ → ψ ) → ( ( ¬ φ → ψ ) → ψ ) )", s1, ref="com12", note="com12")
    return lb.build(res)

def prove_pm2_65(sys: System) -> Proof:
    """Theorem *2.65 of [WhiteheadRussell] p. 107.  Proof by contradiction.
    (Contributed by NM, 21-Jun-1993.)  (Proof shortened by Wolf Lammen,
    8-Mar-2013.)
    """
    lb = ProofBuilder(sys, "pm2.65")
    s1 = lb.ref("s1", "( ( φ → ψ ) → ( ¬ φ → ¬ φ ) )", ref="idd", note="idd")
    s2 = lb.ref("s2", "( ( φ → ψ ) → ( ¬ ψ → ¬ φ ) )", ref="con3", note="con3")
    res = lb.ref("res", "( ( φ → ψ ) → ( ( φ → ¬ ψ ) → ¬ φ ) )", s1, s2, ref="jad", note="jad")
    return lb.build(res)

def prove_pm2_65i(sys: System) -> Proof:
    """Inference for proof by contradiction.  (Contributed by NM, 18-May-1994.)
    (Proof shortened by Wolf Lammen, 11-Sep-2013.)  (Proof shortened by
    Garrett Katz, 7-Jun-2026.)
    """
    lb = ProofBuilder(sys, "pm2.65i")
    h1 = lb.hyp("pm2.65i.1", "( φ → ψ )")
    h2 = lb.hyp("pm2.65i.2", "( φ → ¬ ψ )")
    s1 = lb.ref("s1", "( φ → ¬ φ )", h2, h1, ref="nsyl3", note="nsyl3")
    res = lb.ref("res", "¬ φ", s1, ref="pm2.01i", note="pm2.01i")
    return lb.build(res)

def prove_pm2_65iOLD(sys: System) -> Proof:
    """Obsolete version of ~ pm2.65i as of 7-Jun-2026.  Inference for proof by
    contradiction.  (Contributed by NM, 18-May-1994.)  (Proof shortened by
    Wolf Lammen, 11-Sep-2013.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "pm2.65iOLD")
    h1 = lb.hyp("pm2.65i.1", "( φ → ψ )")
    h2 = lb.hyp("pm2.65i.2", "( φ → ¬ ψ )")
    s1 = lb.ref("s1", "( ψ → ¬ φ )", h2, ref="con2i", note="con2i")
    s2 = lb.ref("s2", "( ¬ ψ → ¬ φ )", h1, ref="con3i", note="con3i")
    res = lb.ref("res", "¬ φ", s1, s2, ref="pm2.61i", note="pm2.61i")
    return lb.build(res)

def prove_pm2_21dd(sys: System) -> Proof:
    """A contradiction implies anything.  Deduction from ~ pm2.21 .
    (Contributed by Mario Carneiro, 9-Feb-2017.)  (Proof shortened by Wolf
    Lammen, 22-Jul-2019.)
    """
    lb = ProofBuilder(sys, "pm2.21dd")
    h1 = lb.hyp("pm2.21dd.1", "( φ → ψ )")
    h2 = lb.hyp("pm2.21dd.2", "( φ → ¬ ψ )")
    s1 = lb.ref("s1", "¬ φ", h1, h2, ref="pm2.65i", note="pm2.65i")
    res = lb.ref("res", "( φ → χ )", s1, ref="pm2.21i", note="pm2.21i")
    return lb.build(res)

def prove_pm2_65d(sys: System) -> Proof:
    """Deduction for proof by contradiction.  (Contributed by NM, 26-Jun-1994.)
    (Proof shortened by Wolf Lammen, 26-May-2013.)
    """
    lb = ProofBuilder(sys, "pm2.65d")
    h1 = lb.hyp("pm2.65d.1", "( φ → ( ψ → χ ) )")
    h2 = lb.hyp("pm2.65d.2", "( φ → ( ψ → ¬ χ ) )")
    s1 = lb.ref("s1", "( φ → ( ψ → ¬ ψ ) )", h2, h1, ref="nsyld", note="nsyld")
    res = lb.ref("res", "( φ → ¬ ψ )", s1, ref="pm2.01d", note="pm2.01d")
    return lb.build(res)

def prove_mto(sys: System) -> Proof:
    """The rule of modus tollens.  The rule says, "if ` ps ` is not true, and
    ` ph ` implies ` ps ` , then ` ph ` must also be not true".  Modus
    tollens is short for "modus tollendo tollens", a Latin phrase that means
    "the mode that by denying denies" - remark in [Sanford] p. 39.  It is
    also called denying the consequent.  Modus tollens is closely related to
    modus ponens ~ ax-mp .  Note that this rule is also valid in
    intuitionistic logic.  Inference associated with ~ con3i .  (Contributed
    by NM, 19-Aug-1993.)  (Proof shortened by Wolf Lammen, 11-Sep-2013.)
    """
    lb = ProofBuilder(sys, "mto")
    h1 = lb.hyp("mto.1", "¬ ψ")
    h2 = lb.hyp("mto.2", "( φ → ψ )")
    s1 = lb.ref("s1", "( φ → ¬ ψ )", h1, ref="a1i", note="a1i")
    res = lb.ref("res", "¬ φ", h2, s1, ref="pm2.65i", note="pm2.65i")
    return lb.build(res)

def prove_mtod(sys: System) -> Proof:
    """Modus tollens deduction.  (Contributed by NM, 3-Apr-1994.)  (Proof
    shortened by Wolf Lammen, 11-Sep-2013.)
    """
    lb = ProofBuilder(sys, "mtod")
    h1 = lb.hyp("mtod.1", "( φ → ¬ χ )")
    h2 = lb.hyp("mtod.2", "( φ → ( ψ → χ ) )")
    s1 = lb.ref("s1", "( φ → ( ψ → ¬ χ ) )", h1, ref="a1d", note="a1d")
    res = lb.ref("res", "( φ → ¬ ψ )", h2, s1, ref="pm2.65d", note="pm2.65d")
    return lb.build(res)

def prove_mtoi(sys: System) -> Proof:
    """Modus tollens inference.  (Contributed by NM, 5-Jul-1994.)  (Proof
    shortened by Wolf Lammen, 15-Sep-2012.)
    """
    lb = ProofBuilder(sys, "mtoi")
    h1 = lb.hyp("mtoi.1", "¬ χ")
    h2 = lb.hyp("mtoi.2", "( φ → ( ψ → χ ) )")
    s1 = lb.ref("s1", "( φ → ¬ χ )", h1, ref="a1i", note="a1i")
    res = lb.ref("res", "( φ → ¬ ψ )", s1, h2, ref="mtod", note="mtod")
    return lb.build(res)

def prove_mt2(sys: System) -> Proof:
    """A rule similar to modus tollens.  Inference associated with ~ con2i .
    (Contributed by NM, 19-Aug-1993.)  (Proof shortened by Wolf Lammen,
    10-Sep-2013.)
    """
    lb = ProofBuilder(sys, "mt2")
    h1 = lb.hyp("mt2.1", "ψ")
    h2 = lb.hyp("mt2.2", "( φ → ¬ ψ )")
    s1 = lb.ref("s1", "( φ → ψ )", h1, ref="a1i", note="a1i")
    res = lb.ref("res", "¬ φ", s1, h2, ref="pm2.65i", note="pm2.65i")
    return lb.build(res)

def prove_mt3(sys: System) -> Proof:
    """A rule similar to modus tollens.  Inference associated with ~ con1i .
    (Contributed by NM, 18-May-1994.)  (Proof shortened by Wolf Lammen,
    11-Sep-2013.)
    """
    lb = ProofBuilder(sys, "mt3")
    h1 = lb.hyp("mt3.1", "¬ ψ")
    h2 = lb.hyp("mt3.2", "( ¬ φ → ψ )")
    s1 = lb.ref("s1", "¬ ¬ φ", h1, h2, ref="mto", note="mto")
    res = lb.ref("res", "φ", s1, ref="notnotri", note="notnotri")
    return lb.build(res)

def prove_peirce(sys: System) -> Proof:
    """Peirce's axiom.  A non-intuitionistic implication-only statement.  Added
    to intuitionistic (implicational) propositional calculus, it gives
    classical (implicational) propositional calculus.  For another
    non-intuitionistic positive statement, see ~ curryax .  When ` F. ` is
    substituted for ` ps ` , then this becomes the Clavius law ~ pm2.18 .
    (Contributed by NM, 29-Dec-1992.)  (Proof shortened by Wolf Lammen,
    9-Oct-2012.)
    """
    lb = ProofBuilder(sys, "peirce")
    s1 = lb.ref("s1", "( ¬ ( φ → ψ ) → φ )", ref="simplim", note="simplim")
    s2 = lb.ref("s2", "( φ → φ )", ref="id", note="id")
    res = lb.ref("res", "( ( ( φ → ψ ) → φ ) → φ )", s1, s2, ref="ja", note="ja")
    return lb.build(res)

def prove_looinv(sys: System) -> Proof:
    """The Inversion Axiom of the infinite-valued sentential logic (L-infinity)
    of Lukasiewicz.  Using ~ dfor2 , we can see that this essentially
    expresses "disjunction commutes".  Theorem *2.69 of [WhiteheadRussell]
    p. 108.  It is a special instance of the axiom "Roll", see ~ peirceroll .
    (Contributed by NM, 12-Aug-2004.)
    """
    lb = ProofBuilder(sys, "looinv")
    s1 = lb.ref("s1", "( ( ( φ → ψ ) → ψ ) → ( ( ψ → φ ) → ( ( φ → ψ ) → φ ) ) )", ref="imim1", note="imim1")
    s2 = lb.ref("s2", "( ( ( φ → ψ ) → φ ) → φ )", ref="peirce", note="peirce")
    res = lb.ref("res", "( ( ( φ → ψ ) → ψ ) → ( ( ψ → φ ) → φ ) )", s1, s2, ref="syl6", note="syl6")
    return lb.build(res)

def prove_bijust0(sys: System) -> Proof:
    """A self-implication (see ~ id ) does not imply its own negation.  The
    justification theorem ~ bijust is one of its instances.  (Contributed by
    NM, 11-May-1999.)  (Proof shortened by Josh Purinton, 29-Dec-2000.)
    Extract ~ bijust0 from proof of ~ bijust .  (Revised by BJ,
    19-Mar-2020.)
    """
    lb = ProofBuilder(sys, "bijust0")
    s1 = lb.ref("s1", "( φ → φ )", ref="id", note="id")
    s2 = lb.ref("s2", "( ( ( φ → φ ) → ¬ ( φ → φ ) ) → ¬ ( φ → φ ) )", ref="pm2.01", note="pm2.01")
    res = lb.ref("res", "¬ ( ( φ → φ ) → ¬ ( φ → φ ) )", s1, s2, ref="mt2", note="mt2")
    return lb.build(res)

def prove_bijust(sys: System) -> Proof:
    """Theorem used to justify the definition of the biconditional ~ df-bi .
    Instance of ~ bijust0 .  (Contributed by NM, 11-May-1999.)
    """
    lb = ProofBuilder(sys, "bijust")
    res = lb.ref("res", "¬ ( ( ¬ ( ( φ → ψ ) → ¬ ( ψ → φ ) ) → ¬ ( ( φ → ψ ) → ¬ ( ψ → φ ) ) ) → ¬ ( ¬ ( ( φ → ψ ) → ¬ ( ψ → φ ) ) → ¬ ( ( φ → ψ ) → ¬ ( ψ → φ ) ) ) )", ref="bijust0", note="bijust0")
    return lb.build(res)


